import React from 'react';
import { Link, useLocation } from 'react-router-dom';

function Navbar() {
  const location = useLocation();
  const links = [
    { name: 'Authority', path: '/authority', icon: '👥' },
    { name: 'Bin', path: '/bin', icon: '🗂️' },
    { name: 'Driver', path: '/driver', icon: '🚗' },
    { name: 'User', path: '/user', icon: '👤' },
    { name: 'Vehicle', path: '/vehicle', icon: '🚛' }
  ];
  
  const navStyles = {
    background: 'rgba(255, 255, 255, 0.95)',
    backdropFilter: 'blur(10px)',
    padding: '15px 0',
    boxShadow: '0 2px 20px rgba(0,0,0,0.1)',
    borderBottom: '1px solid rgba(255,255,255,0.2)',
    position: 'sticky',
    top: 0,
    zIndex: 1000,
  };

  const containerStyles = {
    maxWidth: '1400px',
    margin: '0 auto',
    padding: '0 20px',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'space-between',
  };

  const logoStyles = {
    fontSize: '1.5rem',
    fontWeight: '700',
    color: '#667eea',
    textDecoration: 'none',
    display: 'flex',
    alignItems: 'center',
    gap: '10px',
  };

  const navLinksStyles = {
    display: 'flex',
    gap: '30px',
    alignItems: 'center',
  };

  const linkStyles = (isActive) => ({
    color: isActive ? '#667eea' : '#666',
    textDecoration: 'none',
    padding: '10px 20px',
    borderRadius: '25px',
    fontWeight: '500',
    transition: 'all 0.3s ease',
    background: isActive ? 'rgba(102, 126, 234, 0.1)' : 'transparent',
    border: isActive ? '2px solid #667eea' : '2px solid transparent',
    display: 'flex',
    alignItems: 'center',
    gap: '8px',
    fontSize: '0.95rem',
  });

  const homeLinkStyles = (isActive) => ({
    ...linkStyles(isActive),
    background: isActive ? 'linear-gradient(135deg, #667eea, #764ba2)' : 'linear-gradient(135deg, #667eea, #764ba2)',
    color: 'white',
    fontWeight: '600',
  });
  
  return (
    <nav style={navStyles}>
      <div style={containerStyles}>
        <Link to="/" style={homeLinkStyles(location.pathname === '/')}>
          🏠 Home
        </Link>
        
        <div style={navLinksStyles}>
          {links.map(link => (
            <Link 
              key={link.name} 
              to={link.path} 
              style={linkStyles(location.pathname === link.path)}
            >
              <span>{link.icon}</span>
              {link.name}
            </Link>
          ))}
        </div>
      </div>
    </nav>
  );
}

export default Navbar;
